+        let store = segment_reader.get_store_reader(1024)?;
+        let alive = segment_reader.alive_bitset();
+        for stored_doc in store.iter(alive)? {
+            let stored_doc = stored_doc?;
+
+            let key_u64 = stored_doc
+                .get_first(meta.fields.doc_key)
+                .and_then(|v| v.as_u64())
