+                .and_then(|v| v.as_text())
+                .map(|s| s.to_string());
+            let recorded_modified = stored_doc
+                .get_first(meta.fields.modified)
+                .and_then(|v| v.as_i64())
+                .unwrap_or(0);
+
+            let path = match path {
+                Some(p) => p,
+                None => continue,
